\outl0\strokewidth0 \strokec2 #### 0. Libraries #### library(shiny) library(tidyverse) library(lubridate) library(readxl) library(pracma) # trapz() for AUC #### 1. UI #### ui <- fluidPage( titlePanel("Raneem's GP3 Growth Curve Viewer"), sidebarLayout( sidebarPanel( fileInput("results_file", "Upload reader output (.txt or .csv)", accept = c(".txt", ".csv")), fileInput("plate_map_file", "Upload plate map (.xlsx)", accept = c(".xlsx")), # NEW: optional 2nd sheet to map Strain -> gene/group label fileInput("label_map_file", "Upload OPTIONAL label map (.xlsx) [columns: Strain, Label]", accept = c(".xlsx")), uiOutput("plate_selector"), # NEW: choose whether plots are grouped by Strain or by Label radioButtons( "group_mode", "Show plots grouped by:", choices = c("Strain name" = "strain", "Gene/group label (2nd sheet)" = "label"), selected = "strain" ), # ---- User-editable settings ---- textInput( "blank_wells", "Blank wells (1\'9696, comma-separated)", value = "57,58,59,60,69,70,71,72,81,82,83,84,93,94,95,96" ), textInput( "baseline_condition", "Baseline condition name (e.g. MHB)", value = "MHB" ), textInput( "conditions_keep", "Antibiotic conditions to include (comma-separated)", value = "Imipenem,Meropenem" ), textInput( "concentrations_keep", "Concentrations to keep (comma-separated)", value = "2ug\\\\ml,4ug\\\\ml,8ug\\\\ml" ), # ---- Step 3 controls ---- checkboxInput("remove_outliers", "Remove outliers (IQR method) for the cleaned tab", value = TRUE), numericInput("interval_min", "Time interval between reads (minutes)", value = 40, min = 1, step = 1), # ---- Step 4 controls (kept but not used in barplot mode) ---- selectInput( "auc_mode", "AUC histogram mode", choices = c("pooled", "by strain"), selected = "pooled" ), br(), actionButton("run_btn", "Run analysis", class = "btn-primary"), br(), br(), strong("Downloads:"), br(), downloadButton("download_curves", "Growth curves PDF"), br(), br(), downloadButton("download_boxplots","Boxplots PDF"), br(), br(), helpText("Tip: If you select 'Gene/group label', your label-map file must contain columns Strain + Label.") ), mainPanel( tabsetPanel( tabPanel("Growth curves (replicates)", plotOutput("reps_plot", height = "500px")), tabPanel("Growth curves (mean \'b1 SE)", plotOutput("mean_plot", height = "500px")), tabPanel("Boxplots", plotOutput("boxplot", height = "500px")), tabPanel("Outliers removed (mean \'b1 SE)", plotOutput("mean_plot_clean", height = "500px")), tabPanel("AUC (mean \'b1 SE, outliers removed)", plotOutput("auc_bar", height = "500px")) ) ) ) ) # ---- GLOBAL Y AXIS SETTINGS ---- y_limits <- c(0, 1.2) y_breaks <- seq(0, 1.2, by = 0.2) #### 2. Server #### server <- function(input, output, session) \{ # ----- Read raw reader file ----- raw_data <- reactive(\{ req(input$results_file) read_csv(input$results_file$datapath, col_names = FALSE, show_col_types = FALSE) \}) # ----- Populate plate ID choices ----- observeEvent(raw_data(), \{ df <- raw_data() plate_ids <- sort(unique(df$X1)) output$plate_selector <- renderUI(\{ selectInput("plate_id", "Select plate ID:", choices = plate_ids) \}) \}) # Helper: read optional label map (Strain -> Label) label_map <- reactive(\{ if (is.null(input$label_map_file)) return(NULL) lm <- read_excel(input$label_map_file$datapath) names(lm) <- trimws(names(lm)) # try to find columns case-insensitively nms_low <- tolower(names(lm)) strain_col <- names(lm)[match("strain", nms_low)] label_col <- names(lm)[match("label", nms_low)] # fallback if not found if (is.na(strain_col)) strain_col <- names(lm)[1] if (is.na(label_col)) label_col <- names(lm)[2] lm %>% rename(Strain = all_of(strain_col), Label = all_of(label_col)) %>% mutate(Strain = as.character(Strain), Label = as.character(Label)) %>% filter(!is.na(Strain), Strain != "") \}) # ----- Main analysis (runs when button clicked) ----- analysis <- eventReactive(input$run_btn, \{ req(raw_data(), input$plate_map_file, input$plate_id) plate_id <- input$plate_id raw <- raw_data() # ----- Parse blank wells from user input ----- blank_wells <- strsplit(input$blank_wells, "\\\\s*,\\\\s*")[[1]] blank_wells <- as.integer(blank_wells[blank_wells != ""]) # ----- 1) Read results and reshape to long ----- plate_long <- raw %>% filter(X1 == plate_id) %>% mutate(Time = ymd_hms(paste(X2, X3))) %>% arrange(Time) %>% select(Plate = X1, Time, X5:last_col()) %>% pivot_longer( cols = starts_with("X"), names_to = "WellIndex", values_to = "OD" ) %>% mutate( Well = as.integer(str_extract(WellIndex, "\\\\d+")) - 4L ) %>% select(Plate, Time, Well, OD) # ----- 1b) Time in minutes (every 40 min from start) ----- # (DO NOT change this logic) interval <- input$interval_min time_index_map <- plate_long %>% distinct(Time) %>% arrange(Time) %>% mutate(Time_min = (row_number() - 1) * interval) plate_long <- plate_long %>% left_join(time_index_map, by = "Time") # ----- 2) Blank subtraction ----- blank_means <- plate_long %>% filter(Well %in% blank_wells) %>% group_by(Time) %>% summarise(blank_OD = mean(OD, na.rm = TRUE), .groups = "drop") plate_long <- plate_long %>% left_join(blank_means, by = "Time") %>% mutate( OD_corr = OD - blank_OD, OD_corr = pmax(OD_corr, 0) ) # ----- 3) Read plate map and merge metadata ----- Meta <- read_excel(input$plate_map_file$datapath) names(Meta) <- trimws(names(Meta)) Meta <- Meta %>% rename( Well = wells, Condition = Condition, Concentration = 
\f1\fs26 Concentration (ug/ml)
\f0\fs24  ) %>% mutate( Tag = paste0(Row, Column), Replicate = as.factor(Replicates), Strain = as.character(Strain) ) plate_long <- plate_long %>% left_join(Meta, by = "Well") %>% filter(!is.na(Strain), Strain != "Blank") # ----- NEW: decide plotting/group label ----- lm <- label_map() plate_long <- plate_long %>% mutate(PlotGroup = Strain) if (identical(input$group_mode, "label")) \{ if (is.null(lm)) \{ # If user selected label mode but didn't upload mapping, fallback safely plate_long <- plate_long %>% mutate(PlotGroup = Strain) \} else \{ plate_long <- plate_long %>% left_join(lm, by = "Strain") %>% mutate(PlotGroup = ifelse(!is.na(Label) & Label != "", Label, Strain)) \} \} # ----- 4) User-defined condition filtering ----- cond_vec <- strsplit(input$conditions_keep, "\\\\s*,\\\\s*")[[1]] cond_vec <- cond_vec[cond_vec != ""] conc_vec <- strsplit(input$concentrations_keep, "\\\\s*,\\\\s*")[[1]] conc_vec <- conc_vec[conc_vec != ""] baseline <- input$baseline_condition plate_long_sub <- plate_long %>% filter( (Condition == baseline) | (Condition %in% cond_vec & Concentration %in% conc_vec) ) %>% mutate( CondLabel = case_when( Condition == baseline ~ baseline, TRUE ~ paste0(Condition, " ", Concentration) ) ) # ----- 5) Mean \'b1 SE per group & condition (ALL data) ----- mean_curves <- plate_long_sub %>% group_by(CondLabel, PlotGroup, Time_min) %>% summarise( OD_mean = mean(OD_corr, na.rm = TRUE), OD_se = sd(OD_corr, na.rm = TRUE) / sqrt(n()), .groups = "drop" ) # ----- STEP 3: Outlier detection + cleaned mean curves ----- flagged <- plate_long_sub %>% group_by(CondLabel, PlotGroup, Time_min) %>% mutate( n_rep = sum(!is.na(OD_corr)), Q1 = ifelse(n_rep >= 4, quantile(OD_corr, 0.25, na.rm = TRUE), NA_real_), Q3 = ifelse(n_rep >= 4, quantile(OD_corr, 0.75, na.rm = TRUE), NA_real_), IQRv = Q3 - Q1, lower = Q1 - 1.5 * IQRv, upper = Q3 + 1.5 * IQRv, is_outlier = ifelse(n_rep >= 4, (OD_corr < lower | OD_corr > upper), FALSE) ) %>% ungroup() %>% select(-n_rep, -Q1, -Q3, -IQRv, -lower, -upper) plate_long_clean <- if (isTRUE(input$remove_outliers)) \{ flagged %>% filter(!is_outlier) \} else \{ flagged \} mean_curves_clean <- plate_long_clean %>% group_by(CondLabel, PlotGroup, Time_min) %>% summarise( OD_mean = mean(OD_corr, na.rm = TRUE), OD_se = sd(OD_corr, na.rm = TRUE) / sqrt(n()), .groups = "drop" ) # ----- STEP 4: AUC from outliers-removed data ----- auc_table_clean <- plate_long_clean %>% arrange(CondLabel, PlotGroup, Tag, Replicate, Time_min) %>% group_by(CondLabel, PlotGroup, Tag, Replicate) %>% summarise( AUC = trapz(Time_min, OD_corr), .groups = "drop" ) auc_summary_by_group <- auc_table_clean %>% group_by(CondLabel, PlotGroup) %>% summarise( AUC_mean = mean(AUC, na.rm = TRUE), AUC_se = sd(AUC, na.rm = TRUE) / sqrt(n()), .groups = "drop" ) list( plate_long_sub = plate_long_sub, mean_curves = mean_curves, plate_long_clean = plate_long_clean, mean_curves_clean = mean_curves_clean, auc_table_clean = auc_table_clean, auc_summary_by_group = auc_summary_by_group, plate_id = plate_id ) \}) # ----- Plots ----- output$reps_plot <- renderPlot(\{ a <- analysis(); req(a) ggplot(a$plate_long_sub, aes(x = Time_min, y = OD_corr, group = interaction(PlotGroup, Tag, Replicate), colour = PlotGroup)) + geom_line(alpha = 0.35) + labs( title = paste0("Growth curves - ", a$plate_id, " (blank-corrected, all replicates)"), x = "Time (minutes)", y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 45, hjust = 1), panel.grid.minor.y = element_blank()) \}) output$mean_plot <- renderPlot(\{ a <- analysis(); req(a) ggplot(a$mean_curves, aes(x = Time_min, y = OD_mean, colour = PlotGroup, group = PlotGroup)) + geom_line(size = 1) + geom_ribbon(aes(ymin = OD_mean - OD_se, ymax = OD_mean + OD_se, fill = PlotGroup), alpha = 0.15, colour = NA) + labs( title = paste0("Mean growth curves - ", a$plate_id, " (mean \'b1 SE, all data)"), x = "Time (minutes)", y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 45, hjust = 1), panel.grid.minor.y = element_blank()) \}) output$boxplot <- renderPlot(\{ a <- analysis(); req(a) ggplot(a$plate_long_sub, aes(x = PlotGroup, y = OD_corr, fill = PlotGroup)) + geom_boxplot(alpha = 0.6, outlier.colour = "red", outlier.size = 2) + labs( title = paste0("OD distribution - ", a$plate_id, " (red points = potential outliers)"), x = ifelse(input$group_mode == "label", "Gene/group label", "Strain"), y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 90, vjust = 0.5, hjust = 1), panel.grid.minor.y = element_blank(), legend.position = "none") \}) output$mean_plot_clean <- renderPlot(\{ a <- analysis(); req(a) ggplot(a$mean_curves_clean, aes(x = Time_min, y = OD_mean, colour = PlotGroup, group = PlotGroup)) + geom_line(size = 1) + geom_ribbon(aes(ymin = OD_mean - OD_se, ymax = OD_mean + OD_se, fill = PlotGroup), alpha = 0.15, colour = NA) + labs( title = paste0("Mean growth curves - ", a$plate_id, ifelse(isTRUE(input$remove_outliers), " (outliers removed)", " (outlier removal OFF)")), x = "Time (minutes)", y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 45, hjust = 1), panel.grid.minor.y = element_blank()) \}) # AUC barplot (mean \'b1 SE) like your example output$auc_bar <- renderPlot(\{ a <- analysis(); req(a) pdat <- a$auc_summary_by_group %>% mutate(PlotGroup = as.factor(PlotGroup)) %>% arrange(CondLabel, PlotGroup) ggplot(pdat, aes(x = PlotGroup, y = AUC_mean, fill = PlotGroup)) + geom_col(width = 0.8) + geom_errorbar(aes(ymin = AUC_mean - AUC_se, ymax = AUC_mean + AUC_se), width = 0.2) + facet_wrap(~ CondLabel, scales = "free_y") + labs( title = paste0("AUC (mean \'b1 SE, outliers removed) - ", a$plate_id), x = ifelse(input$group_mode == "label", "Gene/group label", "Strain"), y = "AUC (OD \'d7 minutes) \'b1 SE" ) + theme_bw() + theme( axis.text.x = element_text(angle = 90, vjust = 0.5, hjust = 1), legend.position = "none" ) \}) # ----- Download handlers (unchanged logic) ----- output$download_curves <- downloadHandler( filename = function() \{ a <- analysis(); req(a) paste0("growth_curves_", a$plate_id, ".pdf") \}, content = function(file) \{ a <- analysis(); req(a) pdf(file, width = 9, height = 6) p_reps <- ggplot(a$plate_long_sub, aes(x = Time_min, y = OD_corr, group = interaction(PlotGroup, Tag, Replicate), colour = PlotGroup)) + geom_line(alpha = 0.35) + labs( title = paste0("Growth curves - ", a$plate_id, " (blank-corrected, all replicates)"), x = "Time (minutes)", y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 45, hjust = 1), panel.grid.minor.y = element_blank()) print(p_reps) p_mean <- ggplot(a$mean_curves, aes(x = Time_min, y = OD_mean, colour = PlotGroup, group = PlotGroup)) + geom_line(size = 1) + geom_ribbon(aes(ymin = OD_mean - OD_se, ymax = OD_mean + OD_se, fill = PlotGroup), alpha = 0.15, colour = NA) + labs( title = paste0("Mean growth curves - ", a$plate_id, " (mean \'b1 SE, all data)"), x = "Time (minutes)", y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 45, hjust = 1), panel.grid.minor.y = element_blank()) print(p_mean) dev.off() \} ) output$download_boxplots <- downloadHandler( filename = function() \{ a <- analysis(); req(a) paste0("boxplots_", a$plate_id, ".pdf") \}, content = function(file) \{ a <- analysis(); req(a) pdf(file, width = 10, height = 7) p_box <- ggplot(a$plate_long_sub, aes(x = PlotGroup, y = OD_corr, fill = PlotGroup)) + geom_boxplot(alpha = 0.6, outlier.colour = "red", outlier.size = 2) + labs( title = paste0("OD distribution - ", a$plate_id), x = ifelse(input$group_mode == "label", "Gene/group label", "Strain"), y = "OD600 (blank-corrected)" ) + facet_wrap(~ CondLabel, scales = "fixed") + scale_y_continuous(breaks = y_breaks) + coord_cartesian(ylim = y_limits) + theme_bw() + theme(axis.text.x = element_text(angle = 90, vjust = 0.5, hjust = 1), panel.grid.minor.y = element_blank(), legend.position = "none") print(p_box) dev.off() \} ) \} #### 3. Run app #### shinyApp(ui = ui, server = server)}